-- ================================================================
-- Migration 007 — Chapitres supplémentaires
-- arc_ibrahim (3-5), arc_ismail (2-4), arc_isra_miraj (2-4)
-- Sources : Coran et Sîra uniquement.
-- Aucun dialogue inventé dans la bouche des prophètes.
-- ================================================================

-- ─────────────────────────────────────────────────────────────
-- ARC IBRAHIM — chapitres 3, 4, 5
-- ─────────────────────────────────────────────────────────────

insert into story_chapters (story_id, chapter_number, title, narrative, vocabulary, questions, values_shown, rewards)
values (
  'arc_ibrahim', 3, 'Le départ vers la Terre promise',
  E'Je suis un tapis de voyage — tissé en Perse, usé par les pistes du désert. J''ai traversé bien des pays, mais aucun voyage ne m''a autant marqué que celui d''Ibrahim quittant Babylone.\n\nAprès l''épreuve du feu, les habitants de Babylone avaient été témoins d''un miracle qu''ils ne pouvaient nier. Pourtant, beaucoup refusèrent de croire. Le Coran nous dit : "Nous le sauvâmes, lui et Lot, vers la terre que Nous avions bénie pour les mondes." (Sourate Al-Anbiya, 21:71)\n\nIbrahim part. Avec lui, sa femme Sarah et son neveu Lot. Il laisse derrière lui sa famille, son pays, tout ce qu''il connaît — uniquement parce qu''Allah le lui ordonne. Cette migration volontaire pour Allah s''appelle la hijra.\n\nLe Coran nous décrit Ibrahim dans une supplication sincère avant son départ : "Mon Seigneur, fais-moi entrer d''une entrée de vérité et fais-moi sortir d''une sortie de vérité, et accorde-moi de Ta part une puissance salvatrice." (Sourate Al-Isra, 17:80)\n\nCe n''est pas une fuite. C''est un départ vers Allah. Ibrahim ne sait pas encore ce que la Terre promise lui réserve — mais il sait Qui l''y envoie.\n\nLe tapis comprend, dans ses fils tissés de voyages, que l''exil volontaire pour Allah n''est pas une perte. C''est le début de quelque chose de plus grand que ce qu''on laisse.\n\nLa leçon du tapis : Ibrahim n''a pas cherché une nouvelle patrie. Il a cherché la satisfaction d''Allah — et la patrie est venue en plus.',
  '[{"word_ar": "هِجْرَة", "translit": "hijra", "definition_fr": "migration / départ volontaire pour Allah", "example": "وَمَن يُهَاجِرْ فِي سَبِيلِ اللَّهِ يَجِدْ فِي الْأَرْضِ مُرَاغَمًا كَثِيرًا (celui qui migre dans le chemin d''Allah trouvera sur terre de nombreuses ressources) — Sourate An-Nisa, 4:100"}]',
  '[{"id":"ib3_q1","type":"comprehension","text":"Selon le Coran (21:71), vers où Allah sauva-t-Il Ibrahim et Lot après l''épreuve du feu ?","options":[{"text":"Vers l''Égypte","correct":false},{"text":"Vers la terre que Nous avions bénie pour les mondes","correct":true},{"text":"Vers La Mecque","correct":false},{"text":"Vers le Sinaï","correct":false}]},{"id":"ib3_q2","type":"vocabulary","text":"Quel mot arabe désigne la migration volontaire pour Allah ?","options":[{"text":"سَفَر (safar)","correct":false},{"text":"هِجْرَة (hijra)","correct":true},{"text":"رِحْلَة (rihla)","correct":false},{"text":"خُرُوج (khuruj)","correct":false}]},{"id":"ib3_q3","type":"reflection","text":"Ibrahim quitte tout ce qu''il connaît pour obéir à Allah. Y a-t-il des choses dans ta vie que tu renoncerais à garder par amour d''Allah ?","reflection_prompt":"Le tapis t''écoute sans jugement."},{"id":"ib3_q4","type":"spaced_repetition","text":"Rappel des chapitres précédents : تَوْحِيد (tawhid) et خَلِيل (khalil). Nouveau mot : هِجْرَة (hijra) = migration pour Allah.","options":[],"spaced_ref":"ib3_q2"}]',
  ARRAY['detachement','obeissance','confiance'],
  '{"xp": 55, "coins": 16}'
),
(
  'arc_ibrahim', 4, 'Le songe du sacrifice',
  E'Je suis un tapis de la vallée de Mina, non loin de La Mecque. Les pierres y sont blanches, le ciel immense. Je ne savais pas encore que ce lieu deviendrait l''un des plus sacrés de la terre.\n\nIsmaïl avait grandi. La vallée de Bacca — que l''on appellera La Mecque — était devenue son foyer. Ibrahim venait lui rendre visite.\n\nEt lors d''une de ces visites, Ibrahim reçut un songe. Le Coran nous rapporte sa parole à son fils — non pas comme un ordre brutal, mais comme une consultation pleine de tendresse : "Mon fils, je vois en songe que je t''immole. Vois ce que tu en penses." (Sourate As-Saffat, 37:102)\n\nNotez : Ibrahim ne cache pas le songe à Ismaïl. Il lui en parle, lui demande son avis — parce qu''Ismaïl aussi est concerné dans cette épreuve. Le Coran ne nous rapporte pas qu''Ibrahim lui dit "je vais le faire" mais "vois ce que tu en penses".\n\nEt la réponse d''Ismaïl — que le Coran nous transmet — est l''une des paroles les plus saisissantes des Écritures : "Ô mon père, fais ce qu''on t''ordonne ! Tu me trouveras, si Allah le veut, parmi les endurants." (Sourate As-Saffat, 37:102)\n\nDeux hommes. Un père et un fils. Tous deux soumis à Allah.\n\nLa leçon du tapis : le vrai test n''est pas d''obéir quand c''est facile. Ibrahim et Ismaïl obéirent quand c''était le plus difficile.',
  '[{"word_ar": "صَبْر", "translit": "sabr", "definition_fr": "patience, endurance dans l''épreuve", "example": "إِنَّ اللَّهَ مَعَ الصَّابِرِينَ (Allah est avec ceux qui endurent) — Sourate Al-Baqara, 2:153"}]',
  '[{"id":"ib4_q1","type":"comprehension","text":"Comment Ibrahim annonce-t-il à Ismaïl le songe du sacrifice, selon le Coran (37:102) ?","options":[{"text":"Il lui ordonne sans explication","correct":false},{"text":"Il lui demande son avis : \"Vois ce que tu en penses\"","correct":true},{"text":"Il l''endort et procède sans le lui dire","correct":false},{"text":"Il attend que des témoins soient présents","correct":false}]},{"id":"ib4_q2","type":"vocabulary","text":"Quel mot arabe désigne la patience et l''endurance dans l''épreuve ?","options":[{"text":"شُكْر (shukr)","correct":false},{"text":"تَوَاضُع (tawadu)","correct":false},{"text":"صَبْر (sabr)","correct":true},{"text":"حِكْمَة (hikma)","correct":false}]},{"id":"ib4_q3","type":"reflection","text":"Ismaïl accepte librement l''épreuve et promet d''endurer. Qu''est-ce que cela t''apprend sur le sens du mot \"islam\" (soumission à Allah) ?","reflection_prompt":"Réfléchis au lien entre islam et la réponse d''Ismaïl."},{"id":"ib4_q4","type":"spaced_repetition","text":"Retiens : صَبْر (sabr) = patience dans l''épreuve. C''est ce qu''Ismaïl promet à son père.","options":[],"spaced_ref":"ib4_q2"}]',
  ARRAY['soumission','patience','epreuve_ultime'],
  '{"xp": 65, "coins": 20}'
),
(
  'arc_ibrahim', 5, 'La Ka''ba — la Maison d''Allah',
  E'Je suis un tapis de la vallée de Bacca — cette même vallée que Hajar a traversée en courant, là où Zamzam a jailli. Maintenant, des années plus tard, Ibrahim et Ismaïl construisent quelque chose sur cette terre bénie.\n\nLe Coran nous raconte cette scène dans des mots simples mais immenses : "Et voilà qu''Ibrahim élevait les fondations de la Maison avec Ismaïl : Notre Seigneur, accepte de nous. Tu es, en vérité, l''Audient, l''Omniscient." (Sourate Al-Baqara, 2:127)\n\nIls construisent. Et en construisant, ils supplient — comme si l''acte le plus grand peut toujours ne pas être accepté sans la grâce d''Allah.\n\nCette Maison — la Ka''ba — n''est pas une statue. Elle n''a pas de visage, pas de forme divine. C''est un lieu désigné par Allah comme centre de direction pour le monde entier. Quand les musulmans du monde entier prient, ils se tournent vers elle — pas pour l''adorer, mais parce qu''Allah l''a choisie comme point d''unité.\n\nIbrahim supplie Allah d''en faire un lieu de paix, et d''envoyer à cette communauté un prophète venu d''elle. (Sourate Al-Baqara, 2:129). Cette supplication fut exaucée des siècles plus tard — avec la naissance de Muhammad ﷺ, descendant d''Ismaïl.\n\nLa leçon du tapis : Ibrahim a construit une maison pour Allah, en suppliant Allah de l''accepter. Même nos meilleurs actes ont besoin de Sa grâce.',
  '[{"word_ar": "قِبْلَة", "translit": "qibla", "definition_fr": "direction vers laquelle on se tourne pour prier", "example": "فَوَلِّ وَجْهَكَ شَطْرَ الْمَسْجِدِ الْحَرَامِ (tourne ton visage vers la Mosquée Sacrée) — Sourate Al-Baqara, 2:144"}]',
  '[{"id":"ib5_q1","type":"comprehension","text":"Selon le Coran (2:127), qui bâtit les fondations de la Ka''ba ?","options":[{"text":"Ibrahim seul","correct":false},{"text":"Ibrahim et Ismaïl ensemble","correct":true},{"text":"Ibrahim et Hajar","correct":false},{"text":"Les anges sous la direction d''Ibrahim","correct":false}]},{"id":"ib5_q2","type":"vocabulary","text":"Quel mot arabe désigne la direction vers laquelle les musulmans se tournent pour prier ?","options":[{"text":"صَلَاة (salah)","correct":false},{"text":"مَسْجِد (masjid)","correct":false},{"text":"قِبْلَة (qibla)","correct":true},{"text":"كَعْبَة (ka''ba)","correct":false}]},{"id":"ib5_q3","type":"reflection","text":"Ibrahim et Ismaïl suplient Allah d''accepter leur travail même en le faisant. Penses-tu à demander à Allah d''accepter tes bonnes actions quand tu les fais ?","reflection_prompt":"Réfléchis à ta pratique personnelle."},{"id":"ib5_q4","type":"spaced_repetition","text":"Récapitulatif Ibrahim : تَوْحِيد · خَلِيل · هِجْرَة · صَبْر · قِبْلَة. Cinq mots, cinq chapitres.","options":[],"spaced_ref":"ib5_q2"}]',
  ARRAY['tawhid','unité_oumma','supplication'],
  '{"xp": 70, "coins": 22}'
);

