insert into story_chapters (story_id, chapter_number, title, narrative, vocabulary, questions, values_shown, rewards)
values (
  'arc_ismail', 2, 'La Sa''i — sept allers-retours',
  E'Je suis la poussière entre Safa et Marwa — deux collines qui dominent la vallée aride de Bacca. Personne ne me foule encore, car cette vallée est vide. Vide de tout, sauf d''une femme et d''un nourrisson.\n\nHajar court. Elle grimpe sur Safa, scrute l''horizon. Rien. Elle descend, court jusqu''à Marwa, cherche. Rien. Elle recommence. Une fois, deux fois, sept fois.\n\nLe Coran ne décrit pas cette scène dans le détail — mais il lui donne un statut : la Sa''i, cet aller-retour entre Safa et Marwa, est devenu l''un des rites obligatoires du pèlerinage. Allah lui-même dit dans le Coran : "Safa et Marwa sont parmi les symbols d''Allah. Quiconque fait le pèlerinage à la Maison ou la Omra, il ne commet aucun péché à les faire le tour." (Sourate Al-Baqara, 2:158)\n\nSa persévérance — sept courses, sans garantie de résultat visible — a été consacrée. Ses pas répétés dans la poussière sont devenus des pas que des millions d''humains répèteront jusqu''au Jour du Jugement.\n\nEt à la fin du septième aller-retour, l''eau surgit. Zamzam. Non pas parce que Hajar avait trouvé la bonne technique. Mais parce qu''Allah attendait ce moment précis pour répondre.\n\nLa leçon du tapis : la persévérance sans résultat visible n''est pas du temps perdu. C''est de la foi en acte.',
  '[{"word_ar": "صِرَاط", "translit": "sirat", "definition_fr": "chemin, voie droite — le chemin vers Allah", "example": "اهْدِنَا الصِّرَاطَ الْمُسْتَقِيمَ (guide-nous sur le chemin droit) — Sourate Al-Fatiha, 1:6"}]',
  '[{"id":"is2_q1","type":"comprehension","text":"Quel rite islamique du pèlerinage est directement lié à la course de Hajar entre Safa et Marwa ?","options":[{"text":"Le tawaf autour de la Ka''ba","correct":false},{"text":"La Sa''i — sept allers-retours entre Safa et Marwa","correct":true},{"text":"La lapidation à Mina","correct":false},{"text":"La station à Arafat","correct":false}]},{"id":"is2_q2","type":"vocabulary","text":"Quel mot arabe signifie le ''chemin droit'' vers Allah, mentionné dans la Fatiha ?","options":[{"text":"صِرَاط (sirat)","correct":true},{"text":"طَرِيق (tariq)","correct":false},{"text":"سَبِيل (sabil)","correct":false},{"text":"مَنْهَج (manhaj)","correct":false}]},{"id":"is2_q3","type":"reflection","text":"Hajar court sans savoir que chacun de ses pas deviendra un rite pour des millions de personnes. Crois-tu que nos actes sincères ont des conséquences que nous ne pouvons pas voir ?","reflection_prompt":"Prends le temps d''y réfléchir."},{"id":"is2_q4","type":"spaced_repetition","text":"Rappel : شُكْر (shukr) du chapitre 1. Nouveau mot : صِرَاط (sirat) = chemin droit.","options":[],"spaced_ref":"is2_q2"}]',
  ARRAY['perseverance','confiance','foi_en_acte'],
  '{"xp": 55, "coins": 16}'
),
(
  'arc_ismail', 3, 'Ismaïl le soumis',
  E'Je suis le sol de Mina — cette vallée près de La Mecque, là où Ibrahim amena son fils pour l''épreuve suprême. La même pierre blanche. Le même silence.\n\nIsmaïl avait accepté. Ce qu''il avait promis à son père — "tu me trouveras parmi les endurants" — il le tint.\n\nIbrahim se prépare à accomplir ce que le songe lui avait montré. Et au moment de l''acte, le Coran nous dit : "Nous l''appelâmes : ''Ibrahim ! Tu as confirmé le songe.'' Ainsi récompensons-Nous les bienfaisants." (Sourate As-Saffat, 37:104-105)\n\nAllah intervint avant que le sacrifice s''accomplisse. Ibrahim avait passé l''épreuve — non pas en réalisant l''acte jusqu''au bout, mais en ayant la volonté sincère de le faire. La sincérité de l''intime comptait plus que l''acte lui-même.\n\nEt à la place d''Ismaïl, un bélier immense descendit du ciel. (Sourate As-Saffat, 37:107)\n\nCe remplacement est la source de l''Aïd al-Adha — la fête du sacrifice. Chaque année, des millions de musulmans commémorent non pas le sacrifice d''un fils, mais la soumission totale de deux êtres humains à Allah.\n\nIsmaïl n''est pas seulement le fils du sacrifice. Il est le prototype du croyant qui accepte — et dont la soumission est rachetée par la grâce d''Allah.\n\nLa leçon du tapis : Allah ne veut pas notre sang. Il veut notre cœur.',
  '[{"word_ar": "فِدَاء", "translit": "fida", "definition_fr": "rançon, ce qui est donné en échange / rachat", "example": "وَفَدَيْنَاهُ بِذِبْحٍ عَظِيمٍ (et Nous le rachetâmes par un immense sacrifice) — Sourate As-Saffat, 37:107"}]',
  '[{"id":"is3_q1","type":"comprehension","text":"Comment Allah interrompt-Il l''épreuve du sacrifice selon le Coran (37:104-107) ?","options":[{"text":"En envoyant un ange arrêter le bras d''Ibrahim","correct":false},{"text":"En appelant Ibrahim et en envoyant un bélier à la place","correct":true},{"text":"En faisant apparaître Ismaïl invincible","correct":false},{"text":"En envoyant une révélation écrite","correct":false}]},{"id":"is3_q2","type":"vocabulary","text":"Quel mot arabe désigne le rachat — donner quelque chose à la place de quelqu''un d''autre ?","options":[{"text":"هَدِيَّة (hadiya)","correct":false},{"text":"فِدَاء (fida)","correct":true},{"text":"عَطَاء (ata)","correct":false},{"text":"قُرْبَان (qurban)","correct":false}]},{"id":"is3_q3","type":"reflection","text":"Allah dit à Ibrahim : \"Tu as confirmé le songe.\" Cela signifie que l''acte accompli est la sincérité intérieure, pas l''acte lui-même. Comment cette idée change-t-elle ta façon de voir tes propres actes d''adoration ?","reflection_prompt":"Réfléchis à l''intention (niyya) derrière tes actes."},{"id":"is3_q4","type":"spaced_repetition","text":"Mots clés de l''arc Ismaïl : شُكْر · صِرَاط · فِدَاء. Ismaïl = شُكْر (gratitude), Sa''i = صِرَاط (chemin), sacrifice = فِدَاء (rachat).","options":[],"spaced_ref":"is3_q2"}]',
  ARRAY['soumission','sincerite','grace_divine'],
  '{"xp": 65, "coins": 20}'
),
(
  'arc_ismail', 4, 'Le prophète de la langue arabe',
  E'Je suis un tapis tissé en Arabie — mes fils sont de laine de chameau et de fibres du désert. Ismaïl a grandi dans cette vallée, et avec lui a grandi une langue.\n\nIsmaïl ne reste pas un enfant de l''épreuve. Le Coran lui donne un titre complet et distinct : il est un prophète et un messager, envoyé à son peuple. "Et mentionne dans le Livre Ismaïl. Il était véridique dans ses promesses, et il était un messager, un prophète." (Sourate Maryam, 19:54)\n\nVéridique dans ses promesses — صَادِق الوَعْد. Ces trois mots résument Ismaïl. Quand il promit à son père d''endurer, il endura. Quand il construisit la Ka''ba avec Ibrahim, il construisit jusqu''au bout. Quand il appela son peuple à l''adoration d''Allah, il n''abandonna pas.\n\nSes descendants formeront les tribus arabes du Hijaz. Et des siècles plus tard, de sa descendance naîtra Muhammad ﷺ — l''accomplissement de la supplication d''Ibrahim.\n\nIsmaïl est le lien entre la Ka''ba et le Prophète ﷺ. Entre la pierre et la révélation finale. Entre le sacrifice et la miséricorde.\n\nLa leçon du tapis : Ismaïl a honoré chaque parole qu''il a donnée. Sa fidélité à ses promesses — envers son père, envers Allah, envers son peuple — est le fil conducteur de toute sa vie.',
  '[{"word_ar": "صِدْق", "translit": "sidq", "definition_fr": "véridicité, honnêteté, fidélité à la vérité", "example": "وَكَانَ صَادِقَ الْوَعْدِ (il était véridique dans ses promesses) — Sourate Maryam, 19:54"}]',
  '[{"id":"is4_q1","type":"comprehension","text":"Quels deux titres le Coran accorde-t-il à Ismaïl dans la Sourate Maryam (19:54) ?","options":[{"text":"Khalil et Siddiq","correct":false},{"text":"Messager et Prophète","correct":true},{"text":"Nabi et Rasul (synonymes dans ce verset)","correct":false},{"text":"Imam et Khalifa","correct":false}]},{"id":"is4_q2","type":"vocabulary","text":"Quel mot arabe signifie la véridicité, l''honnêteté totale ?","options":[{"text":"إِخْلَاص (ikhlas)","correct":false},{"text":"صِدْق (sidq)","correct":true},{"text":"وَفَاء (wafa)","correct":false},{"text":"أَمَانَة (amana)","correct":false}]},{"id":"is4_q3","type":"reflection","text":"Le Coran décrit Ismaïl comme ''véridique dans ses promesses''. Réfléchis à ta propre relation aux promesses que tu fais — à Allah, à ta famille, à toi-même.","reflection_prompt":"Prends le temps d''être honnête avec toi-même."},{"id":"is4_q4","type":"spaced_repetition","text":"Bilan arc Ismaïl : شُكْر (gratitude) · صِرَاط (chemin) · فِدَاء (rachat) · صِدْق (véridicité). Quatre mots, quatre leçons.","options":[],"spaced_ref":"is4_q2"}]',
  ARRAY['veridicite','prophetie','heritage_ibrahim'],
  '{"xp": 60, "coins": 18}'
);

