-- ─────────────────────────────────────────────────────────────

insert into story_chapters (story_id, chapter_number, title, narrative, vocabulary, questions, values_shown, rewards)
values (
  'arc_isra_miraj', 2, 'Le Miraj — l''ascension vers les cieux',
  E'Je suis un tapis suspendu entre ciel et terre — tissé de lumière, si le tapis pouvait être fait de lumière. Cette nuit-là, après le voyage de La Mecque à Jérusalem, le voyage ne s''est pas arrêté.\n\nDe Jérusalem, le Prophète ﷺ fut élevé vers les cieux. Le Coran évoque cette ascension dans la Sourate An-Najm : "Alors qu''il se trouvait à l''horizon supérieur, il s''approcha et descendit, se trouvant à deux portées d''arc ou plus près encore." (Sourate An-Najm, 53:7-9)\n\nDans les récits authentiques rapportés par Al-Bukhari et Muslim, le Prophète ﷺ traverse les sept cieux. À chaque ciel, il rencontre un prophète. Adam dans le premier. Yahya et Issa dans le second. Youssouf dans le troisième. Idris dans le quatrième. Haroun dans le cinquième. Moussa dans le sixième. Ibrahim dans le septième.\n\nChaque rencontre est une chaîne — une lignée de messagers envoyés par le même Allah, portant le même message fondamental.\n\nAu-delà du dernier ciel, le Prophète ﷺ atteint Sidrat al-Muntaha — le Jujubier de la limite ultime — au-delà duquel nul ne peut aller. (Sourate An-Najm, 53:14)\n\nLa leçon du tapis : le Prophète ﷺ ne part pas seul dans ce voyage. Il est précédé par tous les prophètes — et les rencontre un à un. L''islam n''est pas une rupture avec l''histoire divine. C''est son accomplissement.',
  '[{"word_ar": "مِعْرَاج", "translit": "miraj", "definition_fr": "ascension céleste — le voyage du Prophète ﷺ vers les cieux", "example": "سُبْحَانَ الَّذِي أَسْرَى — et le Miraj est la suite de ce voyage vers les cieux"}]',
  '[{"id":"im2_q1","type":"comprehension","text":"Selon les récits authentiques, quels prophètes le Prophète ﷺ rencontre-t-il lors de l''ascension ?","options":[{"text":"Uniquement Ibrahim et Moussa","correct":false},{"text":"Adam, Yahya, Issa, Youssouf, Idris, Haroun, Moussa, Ibrahim — un à chaque ciel","correct":true},{"text":"Les anges uniquement","correct":false},{"text":"Les compagnons décédés","correct":false}]},{"id":"im2_q2","type":"vocabulary","text":"Quel mot arabe désigne spécifiquement l''ascension céleste du Prophète ﷺ vers les cieux ?","options":[{"text":"إِسْرَاء (isra)","correct":false},{"text":"مِعْرَاج (miraj)","correct":true},{"text":"رِحْلَة (rihla)","correct":false},{"text":"رُؤْيَا (ru''ya)","correct":false}]},{"id":"im2_q3","type":"reflection","text":"Le Prophète ﷺ rencontre tous les prophètes lors de son ascension. Qu''est-ce que cela t''apprend sur le lien entre l''islam et les religions antérieures ?","reflection_prompt":"Réfléchis à la notion de ''chaîne prophétique''."},{"id":"im2_q4","type":"spaced_repetition","text":"Rappel : إِسْرَاء (isra) = voyage nocturne horizontal. Nouveau : مِعْرَاج (miraj) = ascension verticale.","options":[],"spaced_ref":"im2_q2"}]',
  ARRAY['prophetie','unite_des_prophetes','grandeur_divine'],
  '{"xp": 65, "coins": 20}'
),
(
  'arc_isra_miraj', 3, 'Le don des cinq prières',
  E'Je suis un tapis suspendu entre deux obligations — celle de cent, puis de cinquante, puis de cinq. Je témoigne de la négociation la plus belle de l''histoire.\n\nLors du Miraj, le Prophète ﷺ reçut l''obligation de la prière. Dans les récits authentiques rapportés par Al-Bukhari et Muslim, la prière fut d''abord prescrite à cinquante fois par jour.\n\nEn redescendant à travers les cieux, Moussa — que la paix soit sur lui — interpella le Prophète ﷺ : "Ma communauté a essayé avec moins que cela et n''a pas pu tenir. Retourne vers ton Seigneur et demande une réduction."\n\nLe Prophète ﷺ retourna plusieurs fois. Chaque fois, Allah réduisit. Jusqu''à cinq prières.\n\nMoussa dit encore : "Retourne, c''est encore trop." Mais le Prophète ﷺ répondit qu''il avait déjà demandé jusqu''à avoir honte de continuer.\n\nEt Allah dit : "Ces cinq prières sont prescrites et elles valent dans Ma récompense comme cinquante." (Rapporté dans les deux Sahihs)\n\nCinq en acte. Cinquante en valeur. Un cadeau enveloppé dans la miséricorde.\n\nLe Coran ne décrit pas le détail de cette négociation — mais il désigne la prière comme un pilier, une obligation, un lien direct entre le croyant et Allah, sans intermédiaire.\n\nLa leçon du tapis : la prière n''est pas une contrainte imposée du dehors. Elle est un cadeau offert lors du voyage le plus extraordinaire de l''humanité.',
  '[{"word_ar": "صَلَاة", "translit": "salah", "definition_fr": "la prière — lien direct entre le serviteur et Allah", "example": "إِنَّ الصَّلَاةَ كَانَتْ عَلَى الْمُؤْمِنِينَ كِتَابًا مَوْقُوتًا (la prière est une obligation à des temps prescrits pour les croyants) — Sourate An-Nisa, 4:103"}]',
  '[{"id":"im3_q1","type":"comprehension","text":"Combien de prières furent prescrites initialement lors du Miraj selon les récits authentiques ?","options":[{"text":"Cinq","correct":false},{"text":"Dix","correct":false},{"text":"Cinquante","correct":true},{"text":"Cent","correct":false}]},{"id":"im3_q2","type":"vocabulary","text":"Quel mot arabe désigne la prière islamique — le lien direct entre le croyant et Allah ?","options":[{"text":"دُعَاء (du''a)","correct":false},{"text":"صَلَاة (salah)","correct":true},{"text":"ذِكْر (dhikr)","correct":false},{"text":"عِبَادَة (ibada)","correct":false}]},{"id":"im3_q3","type":"reflection","text":"La prière fut donnée lors du voyage le plus extraordinaire de l''histoire — pas par une révélation ordinaire, mais face à face. Comment cela change-t-il ta façon de voir tes prières quotidiennes ?","reflection_prompt":"Prends le temps d''y réfléchir avant de répondre."},{"id":"im3_q4","type":"spaced_repetition","text":"Bilan Miraj : إِسْرَاء · مِعْرَاج · صَلَاة. Le voyage nocturne nous a donné la prière.","options":[],"spaced_ref":"im3_q2"}]',
  ARRAY['priere','misericorde','don_divin'],
  '{"xp": 65, "coins": 20}'
),
(
  'arc_isra_miraj', 4, 'Abu Bakr As-Siddiq — la foi sans preuve',
  E'Je suis un tapis de la maison d''Abu Bakr à La Mecque. J''ai entendu les rires des incrédules ce matin-là. J''ai entendu aussi la réponse de cet homme debout.\n\nLorsque le Prophète ﷺ raconta son voyage nocturne à La Mecque, les réactions furent immédiates. Certains compagnons vacillèrent. Les chefs qurayshites ricanèrent : un voyage à Jérusalem et retour en une nuit ? Impossible.\n\nIls coururent trouver Abu Bakr pour qu''il soit ébranlé lui aussi. Et Abu Bakr — que la paix soit sur lui — posa une seule question : "Est-ce lui qui vous a dit cela ?"\n\n"Oui."\n\n"Alors je le crois."\n\nIl ajouta — selon les récits : "Je le crois dans des choses plus grandes encore : la révélation qui descend du ciel."\n\nC''est ce jour-là, dit-on, qu''il reçut de la bouche même du Prophète ﷺ le titre d''As-Siddiq — le Véridique, celui qui confirme d''emblée.\n\nLe Coran évoque ceux qui croient "bil ghayb" — en ce qui est invisible. (Sourate Al-Baqara, 2:3) Abu Bakr est l''exemple parfait de cette foi : non pas aveugle, mais ancrée dans la confiance qu''il a construite à force de connaître le Prophète ﷺ.\n\nLa leçon du tapis : la vraie foi n''est pas crédulité. C''est la confiance que l''on a bâtie, acte par acte, jour après jour, dans la véridicité de celui qui parle.',
  '[{"word_ar": "غَيْب", "translit": "ghayb", "definition_fr": "l''invisible, le monde caché — ce qui dépasse les sens humains", "example": "الَّذِينَ يُؤْمِنُونَ بِالْغَيْبِ (ceux qui croient en l''invisible) — Sourate Al-Baqara, 2:3"}]',
  '[{"id":"im4_q1","type":"comprehension","text":"Quel titre le Prophète ﷺ donna-t-il à Abu Bakr après sa réaction au récit du voyage nocturne ?","options":[{"text":"Al-Faruq (celui qui distingue)","correct":false},{"text":"As-Siddiq (le Véridique, celui qui confirme)","correct":true},{"text":"Al-Amin (le fiable)","correct":false},{"text":"Dhul-Nurayn (celui aux deux lumières)","correct":false}]},{"id":"im4_q2","type":"vocabulary","text":"Quel mot arabe désigne l''invisible — ce qui dépasse les sens humains mais auquel le croyant croit ?","options":[{"text":"أَخِرَة (akhira)","correct":false},{"text":"رُوح (ruh)","correct":false},{"text":"غَيْب (ghayb)","correct":true},{"text":"بَاطِن (batin)","correct":false}]},{"id":"im4_q3","type":"reflection","text":"Abu Bakr croit sans hésiter, non par naïveté, mais par confiance construite. Quelle est la différence entre confiance aveugle et foi ancrée dans la connaissance ?","reflection_prompt":"Réfléchis à ce que ''croire'' signifie vraiment pour toi."},{"id":"im4_q4","type":"spaced_repetition","text":"Bilan arc Al-Isra wal-Miraj : إِسْرَاء · مِعْرَاج · صَلَاة · غَيْب. La foi en l''invisible est le fil conducteur.","options":[],"spaced_ref":"im4_q2"}]',
  ARRAY['foi','confiance','temoignage'],
  '{"xp": 60, "coins": 18}'
);
